            int h = (i < n) ? heights[i] : 0;
            while (!st.empty() && heights[st.top()] > h) {
                int height = heights[st.top()]; st.pop();
                int left = st.empty() ? -1 : st.top();
                maxArea = max(maxArea, height * (i - left - 1));
            }
            st.push(i);
        }
    }
